render(() => {
    const cartesianGrid = {
        vertical: false,
        horizontal: true,
        strokeDasharray: 0,
        stroke: 'var(--color-light-neutral-400)',
        fill: 'var(--color-light-base-bg-primary)',
    };
    const legend = {
        marginTop: 10,
    };
    const tooltip = {
        separator: ' ',
        offset: 20,
        filterNull: true,
        cursor: {
            stroke: 'var(--color-light-neutral-400)',
            strokeWidth: 1,
        },
        isAnimationActive: true,
        animationBegin: 0,
        animationDuration: 500,
        animationEasing: 'ease',
        arrow: true,
    };
    const brush = {
        dataKey: 'label',
        travellerWidth: 20,
        height: 20,
        alwaysShowText: true,
        stroke: 'var(--color-static-status-blue)',
    };

    const chartBar = (includeValue) => {
        const labels = ['Январь', 'Февраль', 'Март', 'Апрель', 'Май', 'Июнь']
        if (includeValue) {
            return labels.map((label, idx) => ({
            label: label,
            value:  Math.floor(Math.random() * 250) + 10
            }));
        } else {
            return labels;
        }
    };

    const barChartFirst = {
        zIndex: 1,
        chart: 'bar',
        properties: {
            name: 'расход',
            dataKey: 'uv',
            formatter: (decimal) => `${decimal * 1000}`,
            fill: 'var(--color-static-graphic-persimmon)',
        },
        data: chartBar(true),
    };
    const barChartSecond = {
        zIndex: 10,
        chart: 'bar',
        properties: {
            name: 'приход',
            dataKey: 'pv',
            formatter: (decimal) => `${decimal * 1000}`,
            fill: 'var(--color-static-graphic-green-jungle)',
        },
        data: chartBar(true),
    };
    const lineChart = {
        zIndex: 50,
        chart: 'line',
        icon: 'circleLine',
        properties: {
            name: 'остаток',
            dataKey: 'cnt',
            stroke: 'var(--color-static-status-blue)',
            dot: true,
            dotSettings: {
                scale: 1.5,
                initScale: 1,
                width: 18,
                height: 18,
            },
            formatter: (decimal) => `${decimal * 1000}`,
            type: 'monotone',
            strokeWidth: 2,
        },
        data: chartBar(true),
    };
    const composeChart = {
        initMargin: {
            left: 20,
        },
        barSize: 10,
    };
    const xAxis = {
        tickLine: false,
        axisLine: false,
        interval: 'preserveStartEnd',
        tickMargin: 10,
        dataKey: 'label',
    };
    const yAxis = {
        axisLine: false,
        type: 'number',
        tickCount: 6,
        tickLine: false,
        tickMargin: 0,
        tickFormatter: (decimal) => `${decimal}\xa0тыс.`,
    };

    return (
        <div style={{ display: 'flex' }}>
            <div style={{ width: '600px', height: '400px' }}>
                <Chart
                    id='bar-chart'
                    composeChart={composeChart}
                    cartesianGrid={cartesianGrid}
                    xAxis={xAxis}
                    yAxis={yAxis}
                    tooltip={tooltip}
                    legend={legend}
                    brush={brush}
                    labels={chartBar(false)}
                    series={[barChartFirst, barChartSecond, lineChart]}
                />
            </div>
        </div>
    );
});

