render(() => {
    const formatXAxis = (time) => format(time, 'dd LLL');
    const cartesianGrid = {
        stroke: 'var(--color-light-neutral-400)',
        fill: 'var(--color-light-base-bg-primary)',
    };
    const composeChart = {
        barSize: 24,
    };
    const xAxis = {
        axisLine: false,
        type: 'category',
        interval: 'preserveStartEnd',
        minTickGap: 20,
        tickLine: false,
        dataKey: 'label',
        tickFormatter: formatXAxis,
        tickType: 'point',
    };
    const yAxis = {
        axisLine: false,
        type: 'number',
        tickCount: 6,
        interval: 'preserveStartEnd',
        tickLine: false,
        tickSize: 6,
    };
    const legend = {
        verticalAlign: 'top',
        marginTop: 15,
        iconHeight: 20,
    };
    const tooltip = {
        separator: ' ',
        offset: 20,
        filterNull: true,
        cursor: {
            stroke: 'var(--color-light-neutral-400)',
            strokeWidth: 1,
        },
        isAnimationActive: true,
        animationBegin: 0,
        animationDuration: 500,
        animationEasing: 'ease',
        arrow: true,
        labelFormatter: formatXAxis,
    };
    const brush = {
        dataKey: 'label',
        travellerWidth: 20,
        brushMargin: 10,
        height: 20,
        stroke: 'var(--color-static-status-blue)',
        alwaysShowText: true,
        tickFormatter: formatXAxis,
    };

    const chartData = (num, includeValue) => {
        const labels = Array(20).fill(null).map((_, idx) => {
            const date = new Date('2020-12-18');
            date.setDate(date.getDate() + idx);
            return date.getTime();
        });

        if (includeValue) {
            return labels.map((label, idx) => ({
            label: idx === 0 ? label : labels[idx - 1],
            value: idx === 0 ? 15 : Math.floor(Math.random() * num) + 10
            }));
        } else {
            return labels;
        }
    };

    const lineChart = {
        chart: 'line',
        icon: 'strokeCircle',
        properties: {
            name: 'текущий период',
            dataKey: 'b',
            stroke: 'var(--color-static-status-blue)',
            dot: true,
            dotSettings: {
                scale: 1.5,
                initScale: 0,
                width: 18,
                height: 18,
            },
            inheritStroke: true,
            type: 'monotone',
            strokeWidth: 2,
            strokeDasharray: '10 10',
        },
        data: chartData(30, true)
    };
    const areaChart = {
        chart: 'area',
        icon: 'filledCircle',
        offset: 0.1,
        gradient: {
            gid: 'ar-grad',
            points: [
                {
                    offset: 0,
                    stopColor: 'rgba(0, 112, 224, 0.2)',
                    stopOpacity: 1,
                },
                {
                    offset: 95,
                    stopColor: 'rgba(0, 128, 255, 0)',
                    stopOpacity: 1,
                },
            ],
        },
        properties: {
            name: 'предыдущий период',
            dataKey: 'a',
            type: 'monotone',
            stroke: 'var(--color-static-status-blue)',
            dotSettings: {
                scale: 1.5,
                initScale: 0,
                width: 18,
                height: 18,
            },
            dot: true,
            strokeWidth: 2,
        },
        data: chartData(50, true)
    };

    return (
        <div style={{ display: 'flex' }}>
            <div style={{ width: '600px', height: '400px' }}>
                    <Chart
                        id={'line-chart'}
                        composeChart={composeChart}
                        cartesianGrid={cartesianGrid}
                        xAxis={xAxis}
                        yAxis={yAxis}
                        tooltip={tooltip}
                        legend={legend}
                        brush={brush}
                        labels={chartData(30, false)}
                        series={[lineChart, areaChart]}
                    />
            </div>
        </div>
    );
});
